use dashmap::DashMap;use std::sync::Arc;pub struct C{d:Arc<DashMap<String,String>>}impl C{pub fn new()->Self{Self{d:Arc::new(DashMap::new())}}pub fn a(&self,k:String,v:String){self.d.insert(k,v);}pub fn g(&self,k:&str)->Option<String>{self.d.get(k).map(|v|v.clone())}}#[cfg(test)]mod t{use super::*;#[test]fn t(){let c=C::new();c.a("k".into(),"v".into());assert!(c.g("k").is_some());}#[test]fn e(){let c=C::new();assert!(c.g("x").is_none());}}
